using Microsoft.AspNetCore.Mvc; using ModularMonolith.BuildingBlocks.Errors; using ModularMonolith.Modules.Products.Api.Requests; using ModularMonolith.Modules.Products.Application; namespace ModularMonolith.Modules.Products.Api.Controllers;
[ApiController,Route("api/products")] public sealed class ProductsController(ProductsService products):ControllerBase{ [HttpPost] public async Task<ActionResult<ProductResponse>> Create(CreateProductRequest r,CancellationToken ct)=>this.ToActionResult(await products.CreateAsync(r.Name,r.Price,r.AvailableStock,ct)); [HttpGet("{id:guid}")] public async Task<ActionResult<ProductResponse>> Get(Guid id,CancellationToken ct)=>this.ToActionResult(await products.GetAsync(id,ct)); [HttpPost("{id:guid}/activate")] public async Task<ActionResult<ProductResponse>> Activate(Guid id,CancellationToken ct)=>this.ToActionResult(await products.SetActiveAsync(id,true,ct)); [HttpPost("{id:guid}/deactivate")] public async Task<ActionResult<ProductResponse>> Deactivate(Guid id,CancellationToken ct)=>this.ToActionResult(await products.SetActiveAsync(id,false,ct)); [HttpPost("{id:guid}/stock")] public async Task<ActionResult<ProductResponse>> Stock(Guid id,AddStockRequest r,CancellationToken ct)=>this.ToActionResult(await products.AddStockAsync(id,r.Quantity,ct)); [HttpPut("{id:guid}/price")] public async Task<ActionResult<ProductResponse>> Price(Guid id,ChangePriceRequest r,CancellationToken ct)=>this.ToActionResult(await products.ChangePriceAsync(id,r.Price,ct));}
